window.__QUIZ_DATA__=[{"id":"objective>Geography>2016>1","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The scale of the map in statement form is","images":["data:image/png;base64,"],"options":{"A":"1 centimetre on the map represents 1 kilometre on the ground","B":"2 centimetres on the map represent 1 kilometre on the ground","C":"3 centimetres on the map represent 1 kilometre on the ground","D":"4 centimetres on the map represent 1 km on the ground"},"answer":"A","explanation":"The scale of the map in statement form is 1 centimeter on the map represents 1 kilometre on the ground.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>2","subject":"Geography","year":"2016","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Farming is common in the","images":["data:image/png;base64,"],"options":{"A":"north western part of the map","B":"north eastern part of the map","C":"south western part of the map","D":"south eastern part of the map"},"answer":"D","explanation":"Farming is common in the South-eastern part of the map due to the fact that there is scattered vegetation in this area.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>3","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The western part of R. Gembeh flows through","images":["data:image/png;base64,"],"options":{"A":"a delta","B":"a gorge","C":"a leave","D":"an undulating plain"},"answer":"B","explanation":"The Western part of R. Gembeh flows through a gorge.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>4","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The part where R. Isbo meets R. Gembeh is called","images":["data:image/png;base64,"],"options":{"A":"an entrepot","B":"a watershed","C":"a lagoon","D":"a confluence"},"answer":"D","explanation":"The confluence is a point of intersection of two rivers, i.e., it is the point where two rivers meet.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>5","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The Contour interval on the map is","images":["data:image/png;base64,"],"options":{"A":"50 metres","B":"100 metres","C":"150 metres","D":"200 metres"},"answer":"B","explanation":"The contour interval on the mapped area is in the northeast","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>6","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The lowest point in the mapped area is in the","images":["data:image/png;base64,"],"options":{"A":"south-east","B":"north-east","C":"south-west","D":"north-west"},"answer":"B","explanation":"The lowest point in the mapped area is in the northeast.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>7","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The distance as the crow flies from Bebe to Bodel is","images":["data:image/png;base64,"],"options":{"A":"12.75 km","B":"10.00 km","C":"7.25 km","D":"5.25 km"},"answer":"B","explanation":"The distance as the crow flies from Bebe to Bodel is 10.00 km","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>8","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The bearing of Bodel from Bebe is","images":["data:image/png;base64,"],"options":{"A":"25.0o","B":"255o","C":"115.0o","D":"150.0o"},"answer":"B","explanation":"\u21d2 the bearing of Bodel from Bebe is 255o","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>9","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following statements is true about the drainage of the mapped area?","images":["data:image/png;base64,"],"options":{"A":"The watershed from which the rivers take their sources is in the North West","B":"R. Isbo and R. Gembeh are the two rivers that drain the district","C":"R. Gembeh has many distributaries","D":"An oxbow lake has been formed at the point of intersection of R. Isbo and R. Gembeh."},"answer":"B","explanation":"As regards the drainage of the mapped area, R. Isbo and R. Gambeh are the two rivers that drain the district","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>10","subject":"Geography","year":"2016","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The common mode of transportation in the mapped area are","images":["data:image/png;base64,"],"options":{"A":"railway and water","B":"pipeline and railway","C":"road and water","D":"air and water"},"answer":"C","explanation":"The common mode of transportation in the mapped area is road and water.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>11","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"What is the name of the diagram above?","images":["data:image/png;base64,"],"options":{"A":"Line graph","B":"Bar graph","C":"Pie chart","D":"Star graph"},"answer":"B","explanation":"The diagrammatic representation is a bar graph.  Note that there is a space in between two successive bars in a bar chart.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>12","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"How much rice was produced in 2010 by Country X?","images":["data:image/png;base64,"],"options":{"A":"10,000 kilogrammes","B":"20,000 kilogrammes","C":"50,000 kilogrammes","D":"60,000 kilogrammes"},"answer":"C","explanation":"From the bar chart, country  X produces 50,000kg of rice","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>13","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The total production of rice in kilogramme by country X from 2007 to 2010 was","images":["data:image/png;base64,"],"options":{"A":"60,000","B":"105,000","C":"200,000","D":"260,000"},"answer":"B","explanation":"The production of rice by country X between 2007 and 2010 is the sum of the kilogrammes of rice that corresponds with each vertical bar.  It implies that the total production = 50,000kg + 30,000kg + 20,000kg + 5000kg  = 105,000kg","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>14","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"In which year did Country X have the highest production of rice?","images":["data:image/png;base64,"],"options":{"A":"2007","B":"2008","C":"2009","D":"2010"},"answer":"D","explanation":"In 2010, the country recorded the highest production of rice, i.e. 50,000kg.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>15","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The planet which involves around the sun is a clockwise direction is","images":[],"options":{"A":"Jupiter","B":"Mars","C":"Saturn","D":"Uranus"},"answer":"D","explanation":"Uranus is the only planet that rotates on its side, making it appear to spin in a clockwise direction. This is different from most other planets which have a counter-clockwise rotation.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>16","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"In the Southern hemisphere, the Summer Solstice falls on","images":[],"options":{"A":"21 st March","B":"22nd December","C":"23rd September","D":"23rd June"},"answer":"B","explanation":"In the Southern Hemisphere, the Summer Solstice occurs on December 22nd. This is when the Sun is directly over the Tropic of Capricorn, resulting in the longest day of the year in the Southern Hemisphere.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>17","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The planet with the shortest orbit around the sun is","images":[],"options":{"A":"Jupiter","B":"Mars","C":"Mercury","D":"Pluto"},"answer":"C","explanation":"Mercury in the shortest plants to the sun. It has the shortest orbits of all - it goes around the sun in only 88-days.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>18","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What will be the time in Sao Luis, Brazil (Longitude 45ow) when it is noon in London (longitude 0o)?","images":[],"options":{"A":"10.00 pm","B":"10.00 am","C":"9.00 am","D":"7.20 am"},"answer":"C","explanation":"From the information given in the question, the longitudinal difference = 450  It should be noted that 150 = 1 hour  Therefore 450 = 3 hours.  Note that the time in London is noon, 12:00 pm, hence the time in Brazil is 3 hours behind 12 noon, i.e. 9 a.m","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>19","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Isotherm is a line joining places of equal","images":[],"options":{"A":"cloud cover","B":"pressure","C":"rainfall","D":"temperature"},"answer":"D","explanation":"Isotherm is aline on a map connecting points having the same temperature at a given time or an average over a given period.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>20","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The zone layer is found in the","images":[],"options":{"A":"exosphere","B":"ionosphere","C":"stratosphere","D":"troposhere"},"answer":"D","explanation":"Ozone layer is found in troposphere. The ozone layer is a region within the Earth's stratosphere, located approximately 15 to 35 kilometers (9 to 22 miles) above the Earth's surface.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>21","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Calculate the distance between the equator (latitude 0o) and a city Z in Egypt (latitude 30oN)","images":[],"options":{"A":"2,300 km","B":"3,000 km","C":"3,336 km","D":"4, 430 km"},"answer":"C","explanation":"Parameters given:  \u03b8 = Latitudinal difference = 30\u00b0   Recall that;Distance=\u03b8360\u00d72\u03c0R  Distance=30360\u00d72\u00d7227\u00d76370  Distance = 3336km.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>22","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following climatic belts has the highest durnal temperature range?","images":[],"options":{"A":"Desert","B":"Mediterranean","C":"Tropical Continental","D":"Tropical Hinterland"},"answer":"A","explanation":"Durnal temperature range (DTR) is the difference between the daily maximum and minimum temperature. In which Darst has the highest DTR.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>23","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following gases is found in very little quantity in the atmosphere?","images":[],"options":{"A":"Argon","B":"Carbon dioxide","C":"Nitrogen","D":"Oxygen"},"answer":"A","explanation":"Argan which is a noble gas is found in very little quantities among all the gasses in the option.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>24","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Temperature inversion occurs when","images":[],"options":{"A":"warm air rises over cold air in the tropics","B":"temperature remains the same with height","C":"temperature increases with horizontal distance","D":"temperature increases with height"},"answer":"D","explanation":"Temperature inversion is a reversal of the normal behavior of temperature in the troposphere, where the air temperature increases with height. This is contrary to the normal decrease of temperature with height in the atmosphere. In a temperature inversion, the temperature increases with height.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2016>25","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Circular depression formed in the bed of an upper course river is known as","images":[],"options":{"A":"interlocking spurs","B":"plunge pools","C":"rapids","D":"potholes"},"answer":"D","explanation":"A pothole is a circular depression formed in the bed of an upper course river. It is created by the erosive action of pebbles and small stones whirled around by the river's eddying current.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>26","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The most satisfactory explanation for the formation of fold mountain is","images":[],"options":{"A":"faulting","B":"vulcanicity","C":"compressional forces","D":"tensional forces"},"answer":"A","explanation":"Faulting is  plane fracture or discontinuity in a volume of rock which brings about the formation of fold mountain.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2016>27","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The cooling and solidification of magma within the earth's crust result in formation of a","images":[],"options":{"A":"cinda cone","B":"composite cone","C":"lacclith","D":"lava plateau"},"answer":"C","explanation":"The cooling and solidification of magma within the earth's crust result in the formation of a laccolith. A laccolith is a large igneous intrusion that has been forced between two layers of sedimentary rock. The magma, which is highly viscous, does not flow easily and therefore does not spread out over a large surface area. Instead, it pushes the overlying strata into a dome shape.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>28","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"In an oasis, water is derived from","images":[],"options":{"A":"bajada","B":"underground","C":"rainfall","D":"playa"},"answer":"B","explanation":"Oasis is an isolated Area in a desert, typically surrounding a springs similar water source which the source is from underground.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>29","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The unfolded portion of a fold mountain is called","images":[],"options":{"A":"sial","B":"anticline","C":"syncline","D":"sill"},"answer":"B","explanation":"Anticlines and Syncline are the most common up and down folds that result from compression but due to the n-shape Anticlines, it exhibit some unfolded part.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2016>30","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following features is produced as a result of river capture?","images":[],"options":{"A":"Wind gap","B":"River terrace","C":"Gorge","D":"Incised meander"},"answer":"A","explanation":"River capture, also known as stream piracy, is a geomorphological phenomenon occurring when a stream or river drainage system or watershed is diverted from its own bed, and flows instead down the bed of a neighbouring stream. This can happen for a variety of reasons, including tectonic earth movements, natural damming, or changes in vegetation. The feature produced as a result of river capture is a wind gap. A wind gap is a notch in the hills or mountains through which a watercourse once flowed but is now dry as a result of stream capture.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2016>31","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Tilting of tree trunks, poles and piling of soil behind a wall are effects of","images":[],"options":{"A":"mud flow","B":"soil creep","C":"rock slide","D":"rock slab"},"answer":"B","explanation":"Soil creep is a very slow downhill movement of soil and rock fragments under the influence of gravity. It's so slow that it's usually not noticeable, except over long periods. The tilting of tree trunks, poles and the piling of soil behind a wall are all effects of soil creep. The soil moves downhill, causing things in the soil like trees and poles to tilt. The soil can also pile up behind walls, causing them to bulge or crack.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>32","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Exfoliation of rock is as a result of","images":[],"options":{"A":"weathering by oxidation","B":"weathering by means of solution","C":"mechanical weathering","D":"biological weathering"},"answer":"C","explanation":"Ex foliation of rocks which is also called Spheroidal weathering which is brought about by mechanical weathering.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>33","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Spits are formed by","images":[],"options":{"A":"ocean currents and trade winds","B":"wave erosion","C":"long share drift and wave deposition","D":"westerly winds"},"answer":"C","explanation":"Spits are formed when the prevailing wind blows at an angle to the Coastline, resulting in longshore drift and wave deposition.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>34","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"A water table can be described as","images":[],"options":{"A":"a pool of underground water","B":"a line connecting underground spring of equal height","C":"a line indicating the depth of all artesian wells in an area","D":"general level of underground water"},"answer":"D","explanation":"A water table can be described as the general level of underground water. It is the upper surface of the zone of saturation, above which lies the unsaturated zone, where there is air in the pores of the soil or rock. The water table separates these two zones. It rises or falls due to the amount of water seeping into the ground (recharge) and the amount of water being removed from the ground (discharge).","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>35","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Leaching is the","images":[],"options":{"A":"accumulation of soil minerals in one layer of soil","B":"washing down of soil nutrients","C":"erosion of soil from steep slopes","D":"loss of soil moisture"},"answer":"B","explanation":"Leaching is the washing down of soil nutrients. It is a natural process by which water soluble substances (such as calcium, fertilizers, pesticides) are washed out from soil or wastes. These leached out chemicals (leachites) often pollute ground and surface water.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>36","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following features are found in limestone regions?","images":[],"options":{"A":"Swallow holes","B":"Barchans","C":"Buttes","D":"Inselbergs"},"answer":"A","explanation":"Swallow holes are a common feature in limestone regions. They are formed when rainwater, which is slightly acidic due to dissolved carbon dioxide, seeps into the ground and dissolves the limestone, creating holes. Barchans, Buttes, and Inselbergs are not features associated with limestone regions.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2016>37","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"When the roof of a natural arch collapses, the resulting rock pillar left standing in the sea is called","images":[],"options":{"A":"headland","B":"stack","C":"tombolo","D":"wave-cut platform"},"answer":"B","explanation":"Stock is the resulting rock pillar left standing in the sea when the road of a natural arch collapses.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>38","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The high temperature in the interior of the earth may result in the formation of","images":[],"options":{"A":"fold mountain","B":"horst","C":"geyser","D":"rift valley"},"answer":"C","explanation":"Geyser is a vent in Earth's Surface that periodically ejects a column of hot water and stream which also brings about high temperature in the Earth.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2016>39","subject":"Geography","year":"2016","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"African is described as the most Tropical continent because","images":[],"options":{"A":"most part of Africa lies within the tropics","B":"it lies astride the Greenwich meridian","C":"it is far from the equator","D":"it nears the poles"},"answer":"A","explanation":"Africa is described as the most Tropical continent due to most parts of Africa hies within the tropics","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>40","subject":"Geography","year":"2016","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"The introduction of ECOWAS Passport among member Countries is to promote","images":[],"options":{"A":"economic operation","B":"trade among member states","C":"free movement of people in the sub-region","D":"cultural co-operation"},"answer":"C","explanation":"The introduction of ECOWAS passport among members Countries is to promote free movement of people Implemented by waful Under ECOWAS in the sub-region.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>41","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Elements such as wind, water vapour, sunlight and gases which are of benefit to man, animals and plants are called","images":[],"options":{"A":"human resources","B":"atmospheric resources","C":"vegetation resources","D":"water resources"},"answer":"B","explanation":"Atmospheric resources includes wind, water, sunlight and gasses which are beneficial to man, animal and plants.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>42","subject":"Geography","year":"2016","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Which of the following is not a timber producing Country","images":[],"options":{"A":"Gabon","B":"Nigeria","C":"Cote D' Ivoire","D":"Senegal"},"answer":"A","explanation":"Gabon is not a timber producing Country. Others are producing country.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>43","subject":"Geography","year":"2016","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"What is the name of the trade between one country and another?","images":[],"options":{"A":"Domestic trade","B":"Internal trade","C":"International trade","D":"Inter-state trade"},"answer":"C","explanation":"The trade between one country and another is known as International trade. Domestic trade refers to trade within a single country, while internal trade can refer to trade within a specific region or state within a country. Inter-state trade refers to trade between different states within a country.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>44","subject":"Geography","year":"2016","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following settlements is famous for its ecclesiastical functions?","images":[],"options":{"A":"Freetown","B":"London","C":"Lagos","D":"Rome"},"answer":"D","explanation":"Rome is famous for its ecclesiastical functions, being the center of the Roman Catholic Church and the location of the Vatican City. Ecclesiastical functions refer to activities related to the Christian Church. The other cities listed, Freetown, London, and Lagos, while they may have significant religious activities, are not particularly known for their ecclesiastical functions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>45","subject":"Geography","year":"2016","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following cities is both a harbour and a capital?","images":[],"options":{"A":"Accra","B":"Abidjan","C":"Banjul","D":"Abuja"},"answer":"B","explanation":"Abidjan which is the capital of Cote d' lvoire and which is also an habour","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>46","subject":"Geography","year":"2016","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Irrigation projects are commonly found in areas of","images":[],"options":{"A":"low and unreliable rainfall","B":"high surface fluctuations","C":"low rate of evaporation","D":"high volume of rainfall"},"answer":"A","explanation":"Irrigation which is the application of controlled amount of water to plants at needed intervals. In which areas with a low and unliable rainfall needs irrigation project.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2016>47","subject":"Geography","year":"2016","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"All the following lead to the depletion of the ozone layer except","images":[],"options":{"A":"volcanic eruptions","B":"bush burning","C":"combustion of coal and oil","D":"evapotranspiration"},"answer":"D","explanation":"Evapotranspiration is the process by which water is transferred from the land to the atmosphere by Evaporation from the soil and other surfaces which it doesn't depletes ozone layers.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2016>48","subject":"Geography","year":"2016","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"More Hydro-Electric power (H.E.P) projects should be constructed in developing countries because","images":[],"options":{"A":"there is abundant rainfall","B":"there is ever increasing demand for power","C":"skilled labour is abundant","D":"there are many waterfalls on their rivers"},"answer":"D","explanation":"More hydro-electric power projects should be constructed in developing countries due to there are many waterfalls","marks":"1","difficulty":"3"},{"id":"objective>Geography>2016>49","subject":"Geography","year":"2016","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"It is light in weight, a good conductor of electricity and used extensively in the manufacture of aircraft.    This is a valid description of","images":[],"options":{"A":"aluminium","B":"iron","C":"uranium","D":"silver"},"answer":"A","explanation":"All the options can partially or completely conduct Electricity but aluminium which has a special ability due to it lightness, it is a component on an alloy used in Aircraft and it is also a good conductor of Electricity.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2016>50","subject":"Geography","year":"2016","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"A village is characterized by","images":[],"options":{"A":"the presence of several refineries","B":"availability of tertiary health care facilities","C":"developed infrastructural facilities","D":"agriculture and other primary economic activities"},"answer":"D","explanation":"A village is typically characterized by agriculture and other primary economic activities. Primary economic activities are those that involve the direct extraction or harvesting of resources from the environment, such as farming, fishing, and mining. While villages can have developed infrastructural facilities and health care facilities, these are not defining characteristics of a village.","marks":"1","difficulty":"2"}];